        private void UpdateDropdowns()
        {
            try
            {
                IsLoadingDropdowns = true;
                foreach (string mat in Materials)
                {
                    MaterialDropdowns.Add(new MaterialDropdown
                    {
                        Name = mat,
                        TextureOptions = Textures,
                        SelectedDiffuse = MaterialsTextures.GetValueOrDefault(mat)[0],
                        SelectedMask = MaterialsTextures.GetValueOrDefault(mat)[1],
                        SelectedNormal = MaterialsTextures.GetValueOrDefault(mat)[2],
                        SelectedSpecular = MaterialsTextures.GetValueOrDefault(mat)[3],
                        DiffuseTag = $"{mat}0",
                        MaskTag = $"{mat}1",
                        NormalTag = $"{mat}2",
                        SpecularTag = $"{mat}3",
                        SwizzleTag = $"{mat}_Swizzle",
                        MaterialsSwizzle = MaterialsSwizzle,
                        ParentPage = this,
                        IsSwizzled = MaterialsSwizzle.GetValueOrDefault(mat)
                    });
                }
                DynamicExpanderList.ItemsSource = MaterialDropdowns;

                void OnLayoutUpdated(object s, object e)
                {
                    DynamicExpanderList.LayoutUpdated -= OnLayoutUpdated;
                    IsLoadingDropdowns = false;
                }
                DynamicExpanderList.LayoutUpdated += OnLayoutUpdated;
                ConsoleWriteLineSuccess("Updated the dropdowns!");
            }
            catch (Exception ex)
            {
                ConsoleWriteLineError(ex.ToString());
            }
        }

        public void ConsoleWriteLineError(string message)
        {
            Console.ForegroundColor = ConsoleColor.DarkRed;
            Console.WriteLine(message);
            Console.ForegroundColor = ConsoleColor.White;
        }

        public void ConsoleWriteLineSuccess(string message)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine(message);
            Console.ForegroundColor = ConsoleColor.White;
        }

        public void ConsoleWriteLineWarning(string message)
        {
            Console.ForegroundColor = ConsoleColor.DarkYellow;
            Console.WriteLine(message);
            Console.ForegroundColor = ConsoleColor.White;
        }

        public void ConsoleWriteLineTest(string message)
        {
            Console.ForegroundColor = ConsoleColor.Magenta;
            Console.WriteLine(message);
            Console.ForegroundColor = ConsoleColor.White;
        }

        private (bool Success, string ErrorMsg) GetPskData()
        {
            string[] pskPaths = Directory.GetFiles(SourcePath, "*.psk");
            List<string> alreadyUsedMaterials = new List<string>();
            CurrentSkin.CodeName = new DirectoryInfo(InputPath).Name;
            CurrentSkin.CID = $"CID_{CurrentSkin.CodeName}";
            characterCIDTextBox.Text = CurrentSkin.CID;
            TexturesPath = Path.Combine(SourcePath, "Textures");


            Console.WriteLine($"Searching for valid .psk files inside {SourcePath}");
            if (pskPaths.Length == 0) return (false, $"No .psk files found inside {SourcePath}");

            foreach (string pskPath in pskPaths)
            {
                Console.WriteLine($"Checking {Path.GetFileName(pskPath)}'s character part type " +
                $"by file name");
                string pskNameLower = Path.GetFileNameWithoutExtension(pskPath.ToLower());
                string defaultMat = string.Empty;
                List<string> currentPskMaterials = new();

                List<CharacterPart> allCharacterParts = new() { Body, Head, FaceAcc, Hat };

                CharacterPart currentCp = allCharacterParts.FirstOrDefault(cp => pskNameLower.Contains(cp.Type));
                if (currentCp == null)
                {
                    ConsoleWriteLineWarning($"Cannot get the character part type by file name.\nGetting character part by vertex groups...");
                }

                using var r = new BinaryReader(File.OpenRead(pskPath));
                string[] boneNames = null;
                bool[] boneIsUsedAsVertexGroup = null;

                while (r.BaseStream.Position < r.BaseStream.Length)
                {
                    string id = Encoding.ASCII.GetString(r.ReadBytes(24)).Trim();
                    int sz = r.ReadInt32();
                    int ct = r.ReadInt32();

                    if (id.Contains("REFSKELT"))
                    {
                        boneNames = new string[ct];
                        boneIsUsedAsVertexGroup = new bool[ct];
                        for (int i = 0; i < ct; i++)
                        {
                            boneNames[i] = Encoding.ASCII.GetString(r.ReadBytes(64)).Trim('\0').Trim();
                            r.BaseStream.Seek(sz - 64, SeekOrigin.Current);
                        }
                    }
                    else if (id.Contains("RAWWEIGHTS") && boneNames != null)
                    {
                        for (int i = 0; i < ct; i++)
                        {
                            r.BaseStream.Seek(8, SeekOrigin.Current);
                            int boneIndex = r.ReadInt32();
                            if (boneIndex >= 0 && boneIndex < boneIsUsedAsVertexGroup.Length)
                                boneIsUsedAsVertexGroup[boneIndex] = true;
                        }
                    }
                    else if (id.Contains("MATT0000"))
                    {
                        for (int i = 0; i < ct; i++)
                        {
                            string mat = Encoding.ASCII.GetString(r.ReadBytes(64)).Trim('\0').Trim();
                            if (i == 0) defaultMat = mat; //Grabs the first material as default since it's
                                                          //textures are usually used for more materials
                            currentPskMaterials.Add(mat);
                            r.BaseStream.Seek(sz - 64, SeekOrigin.Current);
                        }
                    }
                    else
                    {
                        r.BaseStream.Seek((long)sz * ct, SeekOrigin.Current);
                    }
                }

                if (boneNames == null)
                {
                    return (false, $"Cannot get the character part of {Path.GetFileName(pskPath)} because" +
                    $" it has no bones!");
                }

                else if (currentCp == null)
                {
                    for (int i = 0; i < boneNames.Length; i++)
                    {
                        if (!boneIsUsedAsVertexGroup[i]) continue;
                        string name = boneNames[i].ToLower();

                        if (name.Contains("foot_r") || name.Contains("foot_l") || name.Contains("hand"))
                        {
                            currentCp = Body;
                            break;
                        }
                        else if (name.Contains("r_eye") || name.Contains("l_eye"))
                        {
                            currentCp = Head;
                            break;
                        }
                        else if (name.Contains("dyn") && name.Contains("hair"))
                        {
                            currentCp = FaceAcc;
                            break;
                        }
                        else if (name.Contains("dyn") || name.Contains("hat"))
                        {
                            currentCp = Hat;
                            break;
                        }
                    }
                }
                if (currentCp == null)
                {
                    return (false, $"Cannot get the character part type of " +
                    $"{Path.GetFileName(pskPath)}, because it doesn't have a valid file name " +
                    $"or valid vertex groups!");
                }
                foreach (string mat in currentPskMaterials)
                {
                    if (!alreadyUsedMaterials.Contains(mat))
                    {
                        Materials.Add(mat);
                        alreadyUsedMaterials.Add(mat);
                        MaterialsTextures.TryAdd(mat, ["Default_Diffuse", "Default_Mask",
                        "Default_Normal", "Default_Specular"]);
                        MaterialsCpPart.TryAdd(mat, currentCp);
                        MaterialsSwizzle.Add(mat, allSwizzleCheckBox.IsChecked ?? false);
                    }
                }
                CharacterPartsDefaultMaterial.TryAdd(currentCp, defaultMat);
                currentCp.PskPath = pskPath;
                CharacterParts.Add(currentCp);
                ConsoleWriteLineSuccess($"{Path.GetFileName(pskPath)} is a {currentCp.Type} character part type!");
            }

            if (string.IsNullOrEmpty(Body.PskPath))
            {
                return (false, $"Cannot find a body .psk file in {SourcePath}\nThe character must have at least a body and a head!");
            }
            if (string.IsNullOrEmpty(Head.PskPath))
            {
                return (false, $"Cannot find a head .psk file in {SourcePath}\nThe character must have at least a body and a head!");
            }
            return (true, string.Empty);
        }

        private void ResetCpData()
        {
            for (int i = 0; i < CharacterParts.Count; i++)
            {
                CharacterParts[i].PskPath = string.Empty;
                CharacterParts[i].FbxPath = string.Empty;
            }
            Materials.Clear();
            Textures.Clear();
            MaterialsTextures.Clear();
            MaterialsSwizzle.Clear();
            MaterialsCpPart.Clear();
            CharacterPartsDefaultMaterial.Clear();
            CurrentSkin.CodeName = string.Empty;
            CurrentSkin.SmallIcon = string.Empty;
            CurrentSkin.LargeIcon = string.Empty;
            CurrentSkin.CID = string.Empty;
            characterCIDTextBox.Text = CurrentSkin.CID;
            TexturesPath = string.Empty;
            CharacterParts.Clear();
            MaterialDropdowns.Clear();
        }

        public async void ConvertPskToFbx()
        {
            string exportFbxPath = Path.Combine(SourcePath, "Fbx");
            if (!Directory.Exists(Path.Combine(SourcePath, "Fbx")))
            {
                Directory.CreateDirectory(Path.Combine(InputPath, "Source", "Fbx"));
                Console.WriteLine($"Created Fbx folder at Source folder: " +
                    $"{Path.Combine(CurrentSkin.CodeName, "Source", "Fbx")}");
            }
            Console.WriteLine("Converting .psk files to .fbx");

            foreach (CharacterPart cp in CharacterParts)
            {
                string exportName = $"{CurrentSkin.CodeName}_{cp.Type}";

                await Task.Run(() =>
                {
                    Process blender = Process.Start(App.BlenderPath, $"-b --python \"{ConvertScript}\" -- \"{cp.PskPath}\" " +
                $"\"{Path.Combine(exportFbxPath, $"{exportName}.fbx")}\"");
                    blender.WaitForExit();
                });
                
                ConsoleWriteLineSuccess($"Succesfully converted " +
                $"{Path.Combine(SourcePath, Path.GetFileName(cp.PskPath))}" +
                $" to {Path.Combine(SourcePath, "Fbx", exportName)}.fbx!");
                cp.FbxPath = Path.Combine(SourcePath, "Fbx", exportName);
            }
            try
            {
                LaunchUnrealScript();
            }
            catch (Exception ex) { ConsoleWriteLineError(ex.ToString()); }
        }

        public (bool Success, string ErrorMsg) GetValidTextures()
        {
            List<KeyValuePair<string, int[]>> missingDefaultTextures = DefaultTexturesColors.Where
            (tex => !Path.Exists(Path.Combine(TexturesPath, $"{tex.Key}.png"))).ToList();

            foreach (KeyValuePair<string, int[]> missingDefTex in missingDefaultTextures)
            {
                CreateDefaultTexture(Path.Combine(TexturesPath, $"{missingDefTex.Key}.png"),
                Color.FromArgb(missingDefTex.Value[0], missingDefTex.Value[1], missingDefTex.Value[2], missingDefTex.Value[3]));
                Console.WriteLine($"Created a default {missingDefTex.Key} texture");
            }

            if (!Directory.Exists(TexturesPath))
            {
                ConsoleWriteLineWarning($"{SourcePath}" +
                $" doesn't exist, the skin won't have any textures.");
                return (true, string.Empty);
            }

            Console.WriteLine($"Searching for valid textures inside {TexturesPath}");

            Textures = Directory.GetFiles(TexturesPath, "*.png").ToList().Select(tex => Path.GetFileNameWithoutExtension(tex)).ToList();

            if (Textures.Count == 0)
            {
                ConsoleWriteLineWarning($"No .png files found inside {TexturesPath}, " +
                $"the skin won't have any textures.");
                return (true, string.Empty);
            }

            List<string> texturesLower = Textures.Select(tex => tex.ToLower()).ToList();

            string largeIcon = Textures.FirstOrDefault(tex =>
            (tex.ToLower().Contains("t_soldier") || tex.ToLower().Contains("t-soldier")) && 
            (tex.ToLower().EndsWith("_l") || tex.ToLower().EndsWith("-l")));

            string smallIcon = Textures.FirstOrDefault(tex =>
            (tex.ToLower().Contains("t_soldier") || tex.ToLower().Contains("t-soldier")) &&
            (!tex.ToLower().EndsWith("_l") && !tex.ToLower().EndsWith("-l")));

            List<string> materialTextures = Textures.Where(tex => tex.EndsWith("_D") || tex.EndsWith("_M") ||
            tex.EndsWith("_N") || tex.EndsWith("_S")).ToList();

            foreach (string matTex in materialTextures) FindTexturesMaterial(matTex);

            if (largeIcon != null) CurrentSkin.LargeIcon = largeIcon;
            if (smallIcon != null) CurrentSkin.SmallIcon = smallIcon;

            if (string.IsNullOrEmpty(CurrentSkin.LargeIcon) && !string.IsNullOrEmpty(CurrentSkin.SmallIcon))
            {
                CurrentSkin.LargeIcon = CurrentSkin.SmallIcon;
                ConsoleWriteLineWarning("Cannot find the large icon, the small icon will be used for " +
                "large icon as well.");
            }
            else if (!string.IsNullOrEmpty(CurrentSkin.LargeIcon) && string.IsNullOrEmpty(CurrentSkin.SmallIcon))
            {
                CurrentSkin.SmallIcon = CurrentSkin.LargeIcon;
                ConsoleWriteLineWarning("Cannot find the small icon, the large icon will be used for " +
                " small icon as well.");
            }

            List<string> materialsWithMissingTextures = Materials.Where(mat =>
            MaterialsTextures.GetValueOrDefault(mat)[0] == "Default_Diffuse" &&
            MaterialsTextures.GetValueOrDefault(mat)[1] == "Default_Mask" &&
            MaterialsTextures.GetValueOrDefault(mat)[2] == "Default_Normal" &&
            MaterialsTextures.GetValueOrDefault(mat)[3] == "Default_Specular").ToList();

            foreach (string mat in materialsWithMissingTextures) GuessMaterialsTextures(mat, MaterialsCpPart.GetValueOrDefault(mat));

            return (true, string.Empty);
        }

        private void FindTexturesMaterial(string texture)
        {
            string textureKeyword = texture.Substring(0, texture.Length - 2)
                        .Replace(CurrentSkin.CodeName, "").ToLower();
            string previousSearchElement = textureKeyword + "|";

            while (previousSearchElement != textureKeyword)
            {
                previousSearchElement = textureKeyword;
                textureKeyword =
                textureKeyword.StartsWith("t_") ? textureKeyword.Remove(0, 2) : textureKeyword;
                textureKeyword = textureKeyword.StartsWith($"{CurrentSkin.CodeName.ToLower()}_") ?
                textureKeyword.Remove(0, CurrentSkin.CodeName.Length + 1) : textureKeyword;
                textureKeyword = textureKeyword.StartsWith($"f_med_") ||
                textureKeyword.StartsWith("m_med_") ?
                textureKeyword.Remove(0, 6) : textureKeyword;
            }
            foreach (string splitName in Regex.Split(CurrentSkin.CodeName, @"(?<!^)(?=[A-Z])"))
            {
                textureKeyword = textureKeyword.Replace(splitName.ToLower(), "");
            }

            foreach (string material in Materials)
            {
                string materialForSearching = material.Replace(CurrentSkin.CodeName, "").ToLower();
                if (materialForSearching.EndsWith(textureKeyword))
                {
                    string materialPskName = Path.GetFileName(MaterialsCpPart.GetValueOrDefault(material).PskPath);
                    if (texture.EndsWith("_D"))
                    {
                        Console.WriteLine($"{texture} is a diffuse texture for {material} in {materialPskName}");
                        MaterialsTextures.GetValueOrDefault(material)[0] = texture;
                    }
                    else if (texture.EndsWith("_M"))
                    {
                        Console.WriteLine($"{texture} is a mask texture for {material} in {materialPskName}");
                        MaterialsTextures.GetValueOrDefault(material)[1] = texture;
                    }
                    else if (texture.EndsWith("_N"))
                    {
                        Console.WriteLine($"{texture} is a normal texture for {material} in {materialPskName}");
                        MaterialsTextures.GetValueOrDefault(material)[2] = texture;
                    }
                    else if (texture.EndsWith("_S"))
                    {
                        Console.WriteLine($"{texture} is a specular texture for {material} in {materialPskName}");
                        MaterialsTextures.GetValueOrDefault(material)[3] = texture;
                    }
                }
            }
        }

        private void GuessMaterialsTextures(string mat, CharacterPart cp)
        {
            string cpsDefaultMat = CharacterPartsDefaultMaterial.GetValueOrDefault(cp);

            if (cpsDefaultMat == null)
            {
                ConsoleWriteLineWarning($"Cannot find textures for {mat}");
                return;
            }

            MaterialsTextures.GetValueOrDefault(mat)[0] = MaterialsTextures.GetValueOrDefault(cpsDefaultMat)[0];
            MaterialsTextures.GetValueOrDefault(mat)[1] = MaterialsTextures.GetValueOrDefault(cpsDefaultMat)[1];
            MaterialsTextures.GetValueOrDefault(mat)[2] = MaterialsTextures.GetValueOrDefault(cpsDefaultMat)[2];
            MaterialsTextures.GetValueOrDefault(mat)[3] = MaterialsTextures.GetValueOrDefault(cpsDefaultMat)[3];
        }

        private async void RenderPreviewImage()
        {
            try
            {
                string[] pskPaths = CharacterParts.Select(cp => cp.PskPath).ToArray();
                List<string> materials = new();
                List<string> texturePaths = new();
                List<bool> swizzleMaterials = new();

                foreach (string mat in MaterialsTextures.Keys)
                {
                    materials.Add(mat);
                    texturePaths.AddRange(MaterialsTextures.GetValueOrDefault(mat).Select
                    (tex => Path.Combine(TexturesPath, $"{tex}.png")));
                    swizzleMaterials.Add(MaterialsSwizzle.GetValueOrDefault(mat));
                }

                var exportData = new BlenderExportData
                {
                    Psks = pskPaths,
                    Textures = texturePaths,
                    Swizzle = swizzleMaterials,
                    Materials = materials,
                    RenderPath = Path.Combine(InputPath, "Source", $"{CurrentSkin.CodeName}.png"),
                    LobbyAnimPath = (CurrentSkin.Gender == "Male" ? MaleLobbyAnimPath : FemaleLobbyAnimPath).Replace('\\', '/'),
                    HeadPsk = Head.PskPath
                };

                string jsonString = System.Text.Json.JsonSerializer.Serialize(exportData, AppJsonContext.Default.BlenderExportData);

                // Base64 to prevent spaces or quotes 
                var plainTextBytes = System.Text.Encoding.UTF8.GetBytes(jsonString);
                string base64Json = System.Convert.ToBase64String(plainTextBytes);

                string arguments = $"-b --python \"{RenderScript}\" -- {base64Json}";

                Console.WriteLine("Rendering the preview...");

                await Task.Run(() =>
                {
                    Process blender = Process.Start(App.BlenderPath, arguments);
                    blender.WaitForExit();
                });
                ConsoleWriteLineSuccess("Successfully Rendered the preview image!");

                await Task.Delay(10);

                var bitmap = new BitmapImage { CreateOptions = BitmapCreateOptions.IgnoreImageCache };
                using (var fileStream = System.IO.File.OpenRead(Path.Combine(SourcePath, $"{CurrentSkin.CodeName}.png")))
                {
                    var inMemoryStream = new Windows.Storage.Streams.InMemoryRandomAccessStream();
                    await System.IO.WindowsRuntimeStreamExtensions.AsStreamForWrite(inMemoryStream).WriteAsync(
                        await System.IO.File.ReadAllBytesAsync(Path.Combine(SourcePath, $"{CurrentSkin.CodeName}.png"))
                    );
                    inMemoryStream.Seek(0);

                    await bitmap.SetSourceAsync(inMemoryStream);
                    characterPreview.Source = bitmap;
                }

                if (!string.IsNullOrEmpty(CurrentSkin.LargeIcon))
                {
                    var iconBitmap = new BitmapImage { CreateOptions = BitmapCreateOptions.IgnoreImageCache };
                    string iconPath = Path.Combine(SourcePath, "Textures", $"{CurrentSkin.LargeIcon}.png");

                    var inMemoryStream = new Windows.Storage.Streams.InMemoryRandomAccessStream();
                    byte[] fileBytes = await System.IO.File.ReadAllBytesAsync(iconPath);
                    using (var dataWriter = new Windows.Storage.Streams.DataWriter(inMemoryStream))
                    {
                        dataWriter.WriteBytes(fileBytes);
                        await dataWriter.StoreAsync();
                        await dataWriter.FlushAsync();
                        dataWriter.DetachStream();
                    }
                    inMemoryStream.Seek(0);

                    await iconBitmap.SetSourceAsync(inMemoryStream);
                    iconPreview.Source = iconBitmap;
                }
            }
            catch (Exception ex)
            {
                ConsoleWriteLineError(ex.Message);
            }

        }

        private async void LaunchUnrealScript()
        {
            try
            {
                List<string> meshNames = new();
                List<string> diffuseTexturePaths = new();
                List<string> maskTexturePaths = new();
                List<string> normalTexturePaths = new();
                List<string> specularTexturePaths = new();
                List<string> iconTexturePaths = new();

                if (CurrentSkin.SmallIcon != "")
                {
                    iconTexturePaths.Add(Path.Combine(SourcePath, "Textures", $"{CurrentSkin.SmallIcon}.png"));
                    iconTexturePaths.Add(Path.Combine(SourcePath, "Textures", $"{CurrentSkin.LargeIcon}.png"));
                }
                else iconTexturePaths = [CurrentSkin.SmallIcon, CurrentSkin.LargeIcon];

                string skelTemplatePath = Path.Combine(Path.GetDirectoryName(App.UeProjectPath), "Content",
                "Skeleton_Template.uasset");
                string animBpTemplatePath = Path.Combine(Path.GetDirectoryName(App.UeProjectPath), "Content",
                "AnimBP_Template.uasset");
                string fakeCIDTemplatePath = Path.Combine(Path.GetDirectoryName(App.UeProjectPath), "Content",
                "CID_Template.uasset");
                string cookedCodeNamePath = Path.Combine(CookedAssetsPath, "CustomSkins", CurrentSkin.CodeName);

                if (!File.Exists(skelTemplatePath))
                {
                    File.WriteAllBytes(skelTemplatePath, Convert.FromBase64String(SkeletonBase64));
                    ConsoleWriteLineSuccess($"Created a Skeleton template!");
                }
                if (!File.Exists(animBpTemplatePath))
                {
                    File.WriteAllBytes(animBpTemplatePath, Convert.FromBase64String(AnimBPBase64));
                    ConsoleWriteLineSuccess($"Created an Animation Blueprint template!");
                }
                if (!File.Exists(fakeCIDTemplatePath))
                {
                    File.WriteAllBytes(fakeCIDTemplatePath, Convert.FromBase64String(FakeCIDBase64));
                }
                if (Directory.Exists(cookedCodeNamePath))
                {
                    Directory.Delete(cookedCodeNamePath, true);
                }

                Console.WriteLine("Launching unreal engine...");

                foreach (string mat in MaterialsTextures.Keys)
                {
                    diffuseTexturePaths.Add(Path.Combine(TexturesPath, $"{MaterialsTextures.GetValueOrDefault(mat)[0]}.png"));
                    maskTexturePaths.Add(Path.Combine(TexturesPath, $"{MaterialsTextures.GetValueOrDefault(mat)[1]}.png"));
                    normalTexturePaths.Add(Path.Combine(TexturesPath, $"{MaterialsTextures.GetValueOrDefault(mat)[2]}.png"));
                    specularTexturePaths.Add(Path.Combine(TexturesPath, $"{MaterialsTextures.GetValueOrDefault(mat)[3]}.png"));
                }
                var unrealData = new UnrealExportData()
                {
                    FbxPaths = CharacterParts.Select(cp => $"{cp.FbxPath}.fbx").ToList(),
                    DiffuseTextures = diffuseTexturePaths,
                    MaskTextures = maskTexturePaths,
                    NormalTextures = normalTexturePaths,
                    SpecularTextures = specularTexturePaths,
                    IconTextures = iconTexturePaths,
                    Materials = Materials,
                    CodeName = CurrentSkin.CodeName,
                    MeshNames = CharacterParts.Select(cp => Path.GetFileNameWithoutExtension(cp.FbxPath)).ToList(),
                    CID = CurrentSkin.CID
                };

                string jsonString = System.Text.Json.JsonSerializer.Serialize(unrealData, AppJsonContext.Default.UnrealExportData);
                string tempJsonPath = Path.Combine(Path.GetTempPath(), "ue_import_data.json");
                File.WriteAllText(tempJsonPath, jsonString, new System.Text.UTF8Encoding(false));

                //Format the script path cleanly
                string safeUeScript = UeScript.Replace('\\', '/');

                string arguments = $"\"{App.UeProjectPath}\" -run=PythonScriptCommandlet -script=\"{safeUeScript}\" -NullRHI -NoWindow -Silent";

                Console.WriteLine($"Launching UE with args: {arguments}");

                ProcessStartInfo startInfo = new ProcessStartInfo
                {
                    FileName = App.UeExecutablePath,
                    Arguments = arguments,
                    UseShellExecute = false, //This must be false for EnvironmentVariables to work
                    RedirectStandardOutput = true,
                    RedirectStandardError = true,
                    CreateNoWindow = false
                };

                startInfo.EnvironmentVariables["UFMT_JSON_PATH"] = tempJsonPath;
                using (Process process = new Process { StartInfo = startInfo })
                {
                    process.Start();
                    Task<string> stdoutTask = process.StandardOutput.ReadToEndAsync();
                    Task<string> stderrTask = process.StandardError.ReadToEndAsync();
                    await Task.WhenAll(stdoutTask, stderrTask);
                    await process.WaitForExitAsync();
                    Console.WriteLine(stdoutTask.Result);
                }

                Console.WriteLine("Done!");
                Console.WriteLine("Cooking the newly created assets...");
                await CookProject();
                Console.WriteLine("Done!");
                Console.WriteLine("Creating the CID.json for the AssetRegistry.bin");

                if (App.UeVersion != "UE_4.26_FnGameProj") FixMeshes();
                CreateAssetRegistry();
                CreateCharacterAssets();
                ConsoleWriteLineSuccess("\nYour custom skin is ready! Check the output folder");
            }
            catch (Exception ex)
            {
                ConsoleWriteLineError(ex.Message);
            }
        }

        private void CreateDefaultTexture(string outputPath, Color color)
        {
            using (Bitmap bmp = new Bitmap(1, 1))
            {
                bmp.SetPixel(0, 0, color);
                bmp.Save(outputPath, ImageFormat.Png);
            }
        }

        private async Task CookProject()
        {
            string arguments = $"\"{App.UeProjectPath}\" -run=Cook -TargetPlatform=WindowsNoEditor -unversioned -iterate -NullRHI -NoWindow -Silent";

            ProcessStartInfo startInfo = new ProcessStartInfo
            {
                FileName = App.UeExecutablePath,
                Arguments = arguments,
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = false
            };

            using (Process process = new Process { StartInfo = startInfo })
            {
                process.Start();
                Task<string> stdoutTask = process.StandardOutput.ReadToEndAsync();
                Task<string> stderrTask = process.StandardError.ReadToEndAsync();
                await Task.WhenAll(stdoutTask, stderrTask);
                await process.WaitForExitAsync();
                Console.WriteLine(stdoutTask.Result);
            }

            Console.WriteLine("Cook done!");
        }

        private void CreateAssetRegistry()
        {
            if (!Path.Exists(CookedAssetsPath))
            {
                CookedAssetsPath = Path.Combine(Path.GetDirectoryName(App.UeProjectPath),
                "Saved", "Cooked", "WindowsNoEditor", Path.GetFileNameWithoutExtension(App.UeProjectPath), "Content");
            }
            //Just in case the user has the project folder named differently than the .uproject

            string[] customSkinFolders = Directory.GetDirectories(Path.Combine(CookedAssetsPath, "CustomSkins"));
            List<string> cookedFakeCids = new();
            List<string> jsonCids = new();

            foreach (string customSkinFolder in customSkinFolders)
            {
                string[] cid = Directory.GetFiles(customSkinFolder, "*.uasset");
                if (cid.Length > 0)
                {
                    string currentFoundCid = Path.GetFileNameWithoutExtension(cid[0]);

                    string json = System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(CidJsonBase64));
                    var root = JObject.Parse(json);
                    root["ObjectPath"] = root["ObjectPath"]!.Value<string>()!.Replace(
                        "/Game/Athena/Items/Cosmetics/Characters/CID_Template.CID_Template",
                        $"/Game/Athena/Items/Cosmetics/Characters/{currentFoundCid}.{currentFoundCid}");
                    root["PackageName"] = root["PackageName"]!.Value<string>()!.Replace(
                        "/Game/Athena/Items/Cosmetics/Characters/CID_Template",
                        $"/Game/Athena/Items/Cosmetics/Characters/{currentFoundCid}");
                    root["AssetName"] = root["PackageName"]!.Value<string>()!.Replace(
                        "CID_Template", currentFoundCid);
                    var tagAndValue = root["TagAndValue"]!.ToArray();
                    foreach (var tag in tagAndValue)
                    {
                        if (tag["Item1"]!.Value<string>() == "PrimaryAssetName")
                        {
                            tag["Item2"] = currentFoundCid;
                            break;
                        }
                    }
                    jsonCids.Add(root.ToString(Formatting.Indented));
                }
                else
                {
                    ConsoleWriteLineWarning($"no uasset files found inside {customSkinFolder}");
                }
            }
            string fnGamePath = Path.Combine(InputPath, "Output", "FortniteGame");
            if (!Directory.Exists(fnGamePath))
            {
                Directory.CreateDirectory(fnGamePath);
                Console.WriteLine($"Created {fnGamePath}!");
            }

            AssetRegistryHelper.Inject(AssetRegistryBinBase64, jsonCids.ToArray(), Path.Combine(fnGamePath, "AssetRegistry312398E80AB6209B22CAA2EBAB2DB35B.bin"));
        }

        private void CreateCharacterAssets()
        {
            DirectoryInfo cookedCharacterDirectory = new DirectoryInfo(Path.Combine(CookedAssetsPath, "CustomSkins", CurrentSkin.CodeName));
            string contentFolderPath = Path.Combine(InputPath, "Output", "FortniteGame", "Content", "CustomSkins", CurrentSkin.CodeName);
            string characterPartsPath = Path.Combine(contentFolderPath, "CharacterParts");
            string materialsPath = Path.Combine(contentFolderPath, "Materials");
            if (!Path.Exists(contentFolderPath)) Directory.CreateDirectory(contentFolderPath);

            foreach (DirectoryInfo subFolder in cookedCharacterDirectory.GetDirectories("*", SearchOption.AllDirectories))
            {
                string targetSubDir = subFolder.FullName.Replace(cookedCharacterDirectory.FullName, contentFolderPath);
                Directory.CreateDirectory(targetSubDir);

                foreach (FileInfo file in subFolder.GetFiles())
                {
                    file.CopyTo(Path.Combine(targetSubDir, file.Name), true);
                }
            }
            ConsoleWriteLineSuccess($"Coppied files from {cookedCharacterDirectory} to {contentFolderPath}");
            if (!Path.Exists(characterPartsPath)) Directory.CreateDirectory(characterPartsPath);

            if (CurrentSkin.Gender == "Female")
            {
                Body.uassetFileBase64 = BodyCpFemaleUassetBase64;
                Body.uexpFileBase64 = BodyCpFemaleUexpBase64;
                Head.uassetFileBase64 = HeadCpFemaleUassetBase64;
                Head.uexpFileBase64 = HeadCpFemaleUexpBase64;
                FaceAcc.uassetFileBase64 = FaceAccCpFemaleUassetBase64;
                FaceAcc.uexpFileBase64 = FaceAccCpFemaleUexpBase64;
            }
            else if (CurrentSkin.Gender == "Male")
            {
                Body.uassetFileBase64 = BodyCpMaleUassetBase64;
                Body.uexpFileBase64 = BodyCpMaleUexpBase64;
                Head.uassetFileBase64 = HeadCpMaleUassetBase64;
                Head.uexpFileBase64 = HeadCpMaleUexpBase64;
                FaceAcc.uassetFileBase64 = FaceAccCpMaleUassetBase64;
                FaceAcc.uexpFileBase64 = FaceAccCpMaleUexpBase64;
            }

            foreach (CharacterPart cp in CharacterParts)
            {
                Console.WriteLine($"Currently editing the {cp.Type} of the skin");
                string uassetPath = Path.Combine(characterPartsPath,
                $"CP_{cp.Type}_{CurrentSkin.CodeName}.uasset");
                string uexpPath = Path.Combine(characterPartsPath,
                $"CP_{cp.Type}_{CurrentSkin.CodeName}.uexp");

                File.WriteAllBytes(uassetPath, Convert.FromBase64String(cp.uassetFileBase64));
                File.WriteAllBytes(uexpPath, Convert.FromBase64String(cp.uexpFileBase64));

                var currentCp = new UAsset(uassetPath, EngineVersion.VER_UE4_26);
                var cpExport0 = (NormalExport)currentCp.Exports[0];
                var cpExport1 = (NormalExport)currentCp.Exports[1];
                cpExport1.ObjectName.Value.Value = $"CP_{cp.Type}_{CurrentSkin.CodeName}";
                if (cp.Type != "hat")
                {
                    var animBpData = (SoftObjectPropertyData)cpExport0["AnimClass"];
                    animBpData.Value.AssetPath.AssetName.Value.Value =
                    $"/Game/CustomSkins/{CurrentSkin.CodeName}/Meshes/" +
                    $"{CurrentSkin.CodeName}_{cp.Type}_AnimBP.{CurrentSkin.CodeName}_{cp.Type}_AnimBP_C";

                    Console.WriteLine($"Changed the Animation Blueprint in CP_{cp.Type}_{CurrentSkin.CodeName} to /Game/CustomSkins/{CurrentSkin.CodeName}/Meshes/" +
                    $"{CurrentSkin.CodeName}_{cp.Type}_AnimBP.{CurrentSkin.CodeName}_{cp.Type}_AnimBP_C");
                }
                var mesh = (SoftObjectPropertyData)cpExport1["SkeletalMesh"];
                mesh.Value.AssetPath.AssetName.Value.Value = $"/Game/CustomSkins/{CurrentSkin.CodeName}/Meshes/" +
                $"{CurrentSkin.CodeName}_{cp.Type}.{CurrentSkin.CodeName}_{cp.Type}";
                Console.WriteLine($"Changed the Mesh in CP_{cp.Type}_{CurrentSkin.CodeName} to /Game/CustomSkins/{CurrentSkin.CodeName}/Meshes/" +
                $"{CurrentSkin.CodeName}_{cp.Type}.{CurrentSkin.CodeName}_{cp.Type}");

                Console.WriteLine(uassetPath);
                currentCp.Write(uassetPath);
                ConsoleWriteLineSuccess($"Successfully edited CP_{cp.Type}_{CurrentSkin.CodeName}.uasset and " +
                $"CP_{cp.Type}_{CurrentSkin.CodeName}.uexp");
            }

            foreach (string material in Materials)
            {
                string uassetMaterialPath = Path.Combine(materialsPath, $"{material}.uasset");
                string uexpMaterialPath = Path.Combine(materialsPath, $"{material}.uexp");

                string materialUassetBase64 = 
                MaterialsSwizzle.GetValueOrDefault(material) ? MiSwizzleUassetBase64 : MiNoSwizzleUassetBase64;
                string materialUexpBase64 =
                MaterialsSwizzle.GetValueOrDefault(material) ? MiSwizzleUexpBase64 : MiNoSwizzleUexpBase64; ;

                File.WriteAllBytes(Path.Combine(uassetMaterialPath),
                Convert.FromBase64String(materialUassetBase64));
                File.WriteAllBytes(Path.Combine(uexpMaterialPath),
                Convert.FromBase64String(materialUexpBase64));
                ConsoleWriteLineSuccess($"Created material instance {material}");
                Console.WriteLine($"Editing {material}");

                var currentMi = new UAsset(uassetMaterialPath, EngineVersion.VER_UE4_26);
                var miImportData = currentMi.Imports;
                var miExportData = currentMi.Exports;
                string fnTexturesPath = $"/Game/CustomSkins/{CurrentSkin.CodeName}/Textures/";
                miImportData[11].ObjectName.Value.Value = Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[0]);
                Console.WriteLine($"Changed the diffuse texture path in {material} to {Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[0])}");
                miImportData[12].ObjectName.Value.Value = Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[1]);
                Console.WriteLine($"Changed the mask texture path in {material} to {Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[1])}");
                miImportData[13].ObjectName.Value.Value = Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[2]);
                Console.WriteLine($"Changed the normal texture path in {material} to {Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[2])}");
                miImportData[14].ObjectName.Value.Value = Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[3]);
                Console.WriteLine($"Changed the specular texture path in {material} to {Path.Combine(fnTexturesPath, MaterialsTextures.GetValueOrDefault(material)[3])}");
                miImportData[23].ObjectName.Value.Value = MaterialsTextures.GetValueOrDefault(material)[0];
                Console.WriteLine($"Changed the diffuse texture in {material} to {MaterialsTextures.GetValueOrDefault(material)[0]}");
                miImportData[24].ObjectName.Value.Value = MaterialsTextures.GetValueOrDefault(material)[1];
                Console.WriteLine($"Changed the mask texture in {material} to {MaterialsTextures.GetValueOrDefault(material)[1]}");
